import React, { useState, useEffect } from 'react';
import { useAuth } from '../contexts/AuthContext';

const Students = () => {
  const { hasRole } = useAuth();
  const [students, setStudents] = useState([]);
  const [showModal, setShowModal] = useState(false);
  const [editingStudent, setEditingStudent] = useState(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [formData, setFormData] = useState({
    firstName: '',
    lastName: '',
    email: '',
    phone: '',
    course: '',
    semester: '',
    enrollmentDate: '',
    status: 'Active'
  });

  // Sample data
  const sampleStudents = [
    {
      id: 1,
      firstName: 'Rahul',
      lastName: 'Kumar',
      email: 'rahul.kumar@example.com',
      phone: '+91 9876543210',
      course: 'B.Tech Computer Science',
      semester: 'Semester 3',
      enrollmentDate: '2022-08-15',
      status: 'Active'
    },
    {
      id: 2,
      firstName: 'Priya',
      lastName: 'Sharma',
      email: 'priya.sharma@example.com',
      phone: '+91 9876543211',
      course: 'M.B.A Business Administration',
      semester: 'Semester 2',
      enrollmentDate: '2023-01-10',
      status: 'Active'
    },
    {
      id: 3,
      firstName: 'Amit',
      lastName: 'Singh',
      email: 'amit.singh@example.com',
      phone: '+91 9876543212',
      course: 'B.Sc Physics',
      semester: 'Semester 1',
      enrollmentDate: '2023-08-20',
      status: 'Inactive'
    }
  ];

  useEffect(() => {
    setStudents(sampleStudents);
  }, []);

  // Check if user has permission to access this page
  if (!hasRole('ADMIN')) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="text-center">
          <h1 className="text-2xl font-bold text-gray-900 mb-2">Access Denied</h1>
          <p className="text-gray-600">You don't have permission to access this page.</p>
        </div>
      </div>
    );
  }

  const filteredStudents = students.filter(student =>
    student.firstName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    student.lastName.toLowerCase().includes(searchTerm.toLowerCase()) ||
    student.email.toLowerCase().includes(searchTerm.toLowerCase()) ||
    student.course.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleSubmit = (e) => {
    e.preventDefault();

    if (editingStudent) {
      // Update existing student
      setStudents(students.map(student =>
        student.id === editingStudent.id
          ? { ...formData, id: editingStudent.id }
          : student
      ));
    } else {
      // Add new student
      const newStudent = {
        ...formData,
        id: Math.max(...students.map(s => s.id), 0) + 1
      };
      setStudents([...students, newStudent]);
    }

    resetForm();
  };

  const handleEdit = (student) => {
    setEditingStudent(student);
    setFormData({
      firstName: student.firstName,
      lastName: student.lastName,
      email: student.email,
      phone: student.phone,
      course: student.course,
      semester: student.semester,
      enrollmentDate: student.enrollmentDate,
      status: student.status
    });
    setShowModal(true);
  };

  const handleDelete = (id) => {
    if (window.confirm('Are you sure you want to delete this student?')) {
      setStudents(students.filter(student => student.id !== id));
    }
  };

  const resetForm = () => {
    setFormData({
      firstName: '',
      lastName: '',
      email: '',
      phone: '',
      course: '',
      semester: '',
      enrollmentDate: '',
      status: 'Active'
    });
    setEditingStudent(null);
    setShowModal(false);
  };

  return (
    <div>
      <h1 className="text-2xl font-bold text-gray-900 mb-6">Students Management</h1>

      {/* Search and Add Button */}
      <div className="mb-6 flex justify-between items-center">
        <div className="max-w-md">
          <input
            type="text"
            placeholder="Search students..."
            className="input"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
        <button
          onClick={() => setShowModal(true)}
          className="btn btn-primary"
        >
          Add Student
        </button>
      </div>

      {/* Students Table */}
      <div className="bg-white shadow rounded-lg overflow-hidden">
        <div className="overflow-x-auto">
          <table className="min-w-full divide-y divide-gray-200">
            <thead className="bg-gray-50">
              <tr>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">ID</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Name</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Email</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Phone</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Course</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Semester</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Status</th>
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-gray-200">
              <tr>
                <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">John Doe</td>
                <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">john@example.com</td>
                <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">Computer Science</td>
                <td className="px-6 py-4 whitespace-nowrap">
                  <span className="px-2 inline-flex text-xs leading-5 font-semibold rounded-full bg-green-100 text-green-800">Active</span>
                </td>
              </tr>
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default Students;
